field.placeholder:
{
    "type": "object",
    "properties": {
        "customer_name": {
            "type": "string",
            "description": "Full name of the customer"
        },
        "product_lines": {
            "type": "array",
            "description": "Products to add to the order",
            "items": {
                "type": "object",
                "properties": {
                    "name":       { "type": "string",  "description": "Product name" },
                    "quantity":   { "type": "number",  "description": "Quantity" },
                    "price_unit": { "type": "number",  "description": "Unit price (optional)" }
                },
                "required": ["name", "quantity"]
            }
        }
    },
    "required": ["customer_name", "product_lines"]
}

# Schema properties are injected as local variables
# e.g. customer_name, product_lines

# 1. Find or create customer
partner = env['res.partner'].search(
    [['name', 'ilike', customer_name], ['active', '=', True]], limit=1
)
if not partner:
    partner = env['res.partner'].create({
        'name': customer_name,
        'is_company': True,
        'customer_rank': 1,
    })

# 2. Build order lines
lines = []
for line in product_lines:
    product = env['product.product'].search(
        ['|', ['name', 'ilike', line['name']],
              ['default_code', 'ilike', line['name']]], limit=1
    )
    if not product:
        product = env['product.product'].create({
            'name': line['name'], 'type': 'consu',
            'list_price': line.get('price_unit', 0.0),
        })
    lines.append((0, 0, {
        'product_id': product.id,
        'product_uom_qty': line.get('quantity', 1),
        'price_unit': line.get('price_unit', product.list_price),
    }))

# 3. Create the quotation
order = env['sale.order'].create({
    'partner_id': partner.id,
    'order_line': lines,
})
ai['result'] = f"Quotation {order.name} created for {partner.name}."
